<h1>Requisição a armazém</h1><p class="text-muted">Formulário rápido para chefes de equipa comunicarem necessidades ao departamento de compras/stock.</p><form method="post" action="/?page=request_save" class="row g-2 quick-form mb-4"><div class="col-md-2"><input class="form-control" name="requester" placeholder="Requisitante" required></div><div class="col-md-2"><input class="form-control" name="team" placeholder="Equipa" required></div><div class="col-md-2"><select class="form-select" name="item_id"><?php foreach($items as $i): ?><option value="<?= $i['id'] ?>"><?= htmlspecialchars($i['name']) ?></option><?php endforeach; ?></select></div><div class="col-md-1"><input class="form-control" name="quantity" type="number" step="0.01" placeholder="Qtd" required></div><div class="col-md-2"><select class="form-select" name="status"><option>Pendente</option><option>Aprovado</option><option>Entregue</option></select></div><div class="col-md-2"><input class="form-control" name="notes" placeholder="Notas"></div><div class="col-md-1"><button class="btn btn-primary w-100">Pedir</button></div></form><?php require dirname(__DIR__).'/partials/requests_table.php'; ?>
